import{_ as t,o as a,c as i,ao as r}from"./chunks/framework.BOTctrRk.js";const u=JSON.parse('{"title":"Subagent Model Recommendations","description":"","frontmatter":{},"headers":[],"relativePath":"dev/subagent-models.md","filePath":"dev/subagent-models.md","lastUpdated":null}'),o={name:"dev/subagent-models.md"};function n(s,e,l,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="Subagent-Model-Recommendations" tabindex="-1">Subagent Model Recommendations <a class="header-anchor" href="#Subagent-Model-Recommendations" aria-label="Permalink to &quot;Subagent Model Recommendations {#Subagent-Model-Recommendations}&quot;">​</a></h1><p>When running Claude Code with parallel or serial subagents — for CI scripts, feature work, algorithm research, or documentation — the right model choice avoids paying for power you don&#39;t need and avoids hitting limits on the tasks that do need deep context.</p><h2 id="Model-tiers" tabindex="-1">Model tiers <a class="header-anchor" href="#Model-tiers" aria-label="Permalink to &quot;Model tiers {#Model-tiers}&quot;">​</a></h2><h3 id="Haiku-—-boilerplate,-CI,-workflow-files" tabindex="-1">Haiku — boilerplate, CI, workflow files <a class="header-anchor" href="#Haiku-—-boilerplate,-CI,-workflow-files" aria-label="Permalink to &quot;Haiku — boilerplate, CI, workflow files {#Haiku-—-boilerplate,-CI,-workflow-files}&quot;">​</a></h3><p>Use Haiku for tasks where the output is <strong>well-defined and mechanical</strong>:</p><ul><li><p>GitHub Actions / CI workflow YAML</p></li><li><p>Formatting / linting configuration (<code>.runic.toml</code>, etc.)</p></li><li><p>Changelog and release-note generation from commit messages</p></li><li><p>Dependency bumps and <code>Project.toml</code> edits</p></li><li><p>Simple test stubs from function signatures</p></li><li><p>Scaffold generation (new file from a template)</p></li></ul><p>Haiku is fast and cheap. If the task fits in a tight, concrete prompt with a clear acceptance criterion, Haiku will produce a correct result faster than Sonnet and at a fraction of the cost.</p><h3 id="Sonnet-—-docs,-well-scoped-features,-refactors" tabindex="-1">Sonnet — docs, well-scoped features, refactors <a class="header-anchor" href="#Sonnet-—-docs,-well-scoped-features,-refactors" aria-label="Permalink to &quot;Sonnet — docs, well-scoped features, refactors {#Sonnet-—-docs,-well-scoped-features,-refactors}&quot;">​</a></h3><p>Use Sonnet for tasks that need <strong>sustained reasoning over a few files</strong> but have a clear scope:</p><ul><li><p>Writing or updating documentation pages (like this site)</p></li><li><p>Implementing a well-specified feature (e.g. the <code>prfft</code>/<code>pirfft</code> real-input variant once the interface is defined)</p></li><li><p>Refactoring a module with a known target structure</p></li><li><p>Writing benchmark scripts and plotting utilities</p></li><li><p>Code review at &quot;medium&quot; depth (correctness + simplification)</p></li><li><p>Translating a known algorithm from pseudocode or another language to Julia</p></li></ul><p>Sonnet handles multi-file coherence well and can hold enough context to keep a feature&#39;s API, tests, and docs consistent in a single session.</p><h3 id="Opus-—-hard-perf/algorithm-work,-deep-context" tabindex="-1">Opus — hard perf/algorithm work, deep context <a class="header-anchor" href="#Opus-—-hard-perf/algorithm-work,-deep-context" aria-label="Permalink to &quot;Opus — hard perf/algorithm work, deep context {#Opus-—-hard-perf/algorithm-work,-deep-context}&quot;">​</a></h3><p>Use Opus for tasks where <strong>correctness or performance depends on understanding the full system</strong>:</p><ul><li><p>Designing or debugging a new FFT variant (e.g. a recursive multi-level four-step)</p></li><li><p>Diagnosing a performance regression that requires reading profiler output + LLVM IR + benchmark history simultaneously</p></li><li><p>Architecture decisions that touch multiple abstraction layers (plan dispatch, codelet generation, SIMD layout)</p></li><li><p>Security or correctness reviews that require tracking invariants across many files</p></li><li><p>Any task where you&#39;d say &quot;I need it to read REPORT.md, three source files, and the benchmark output before answering&quot;</p></li></ul><p>Opus is the right choice when the cost of a wrong answer (regression, architectural dead end) is high. For PureFFT specifically: most of the remaining gap to FFTW is in orchestration architecture (recursive multi-level decomposition, codelet scheduling), which is exactly the kind of deep, multi-file reasoning Opus handles better.</p><h2 id="Practical-rules-for-subagents-on-this-project" tabindex="-1">Practical rules for subagents on this project <a class="header-anchor" href="#Practical-rules-for-subagents-on-this-project" aria-label="Permalink to &quot;Practical rules for subagents on this project {#Practical-rules-for-subagents-on-this-project}&quot;">​</a></h2><p><strong>Subagents start cold.</strong> They have no memory of prior sessions. A subagent that opens <code>REPORT.md</code> without being told to will miss the history of what was tried and why. Always include in the prompt:</p><ul><li><p>The relevant excerpt from <code>REPORT.md</code> or <code>bench/rustfft_compare/README.md</code></p></li><li><p>The specific file paths and line numbers to read</p></li><li><p>The known negative findings (so it doesn&#39;t retry a dead end)</p></li></ul><p><strong>Prefer parallel subagents for disjoint scopes.</strong> Tasks that touch different files and have no shared state are safe to run in parallel. Examples:</p><ul><li><p>Haiku writing a GitHub Actions workflow while Sonnet writes a new docs page</p></li><li><p>Two Sonnet agents implementing <code>prfft</code> and <code>pirfft</code> if their implementations are file-separated</p></li><li><p>A Haiku formatting pass running while Sonnet writes tests</p></li></ul><p>Tasks that share state (the same source file, a plan type used by multiple variants) must be serialized or carefully coordinated.</p><p><strong>Match brief depth to model tier.</strong> For Haiku, a tight spec is correct and sufficient (&quot;add a CI job that runs <code>julia --project=bench bench/compare.jl</code> on push to main&quot;). For Opus, invest in a rich brief — include context, constraints, and known-wrong directions, because Opus will explore deeply and a shallow brief wastes its capacity on rediscovering what you already know.</p><h2 id="Quick-reference" tabindex="-1">Quick reference <a class="header-anchor" href="#Quick-reference" aria-label="Permalink to &quot;Quick reference {#Quick-reference}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Task type</th><th style="text-align:right;">Model</th><th style="text-align:right;">Brief depth</th></tr></thead><tbody><tr><td style="text-align:right;">CI/CD, YAML, config</td><td style="text-align:right;">Haiku</td><td style="text-align:right;">Tight spec</td></tr><tr><td style="text-align:right;">Docs, guides, READMEs</td><td style="text-align:right;">Sonnet</td><td style="text-align:right;">Moderate context</td></tr><tr><td style="text-align:right;">New feature (rfft, new variant)</td><td style="text-align:right;">Sonnet</td><td style="text-align:right;">Spec + API contract</td></tr><tr><td style="text-align:right;">Refactor, code review</td><td style="text-align:right;">Sonnet</td><td style="text-align:right;">Scope + acceptance test</td></tr><tr><td style="text-align:right;">Perf diagnosis, algorithm design</td><td style="text-align:right;">Opus</td><td style="text-align:right;">Full history + constraints</td></tr><tr><td style="text-align:right;">Architecture decisions</td><td style="text-align:right;">Opus</td><td style="text-align:right;">Full history + known dead ends</td></tr></tbody></table>',24)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
